package jetbrains.mps.baseLanguage.unitTest.execution.server;

/*Generated by MPS */

import org.junit.platform.launcher.TestExecutionListener;
import org.junit.platform.launcher.TestPlan;
import jetbrains.mps.baseLanguage.unitTest.execution.TestEventMessage;
import java.util.Optional;
import org.junit.platform.launcher.TestIdentifier;
import org.junit.platform.engine.TestExecutionResult;
import org.jetbrains.annotations.NotNull;
import org.junit.platform.engine.TestSource;
import org.junit.platform.engine.support.descriptor.ClassSource;
import org.junit.platform.engine.support.descriptor.MethodSource;

/**
 * Adaptation of {@code DefaultRunListener} class to JUnit5 API. 
 */
public class DefaultTestExecutionListener implements TestExecutionListener {
  private final CommandOutputStream myOutput;

  public DefaultTestExecutionListener(CommandOutputStream out) {
    this.myOutput = out;
  }

  @Override
  public void testPlanExecutionStarted(TestPlan testPlan) {
    flush();
    printSyncToken(TestEventMessage.START_TESTRUN, Optional.<TestIdentifier>empty());
  }

  @Override
  public void testPlanExecutionFinished(TestPlan testPlan) {
    flush();
    printSyncToken(TestEventMessage.FINISH_TESTRUN, Optional.<TestIdentifier>empty());
  }

  @Override
  public void executionStarted(TestIdentifier testIdentifier) {
    // filter out test ids that correspond to JUnit engines being used
    if (!("JUnit Vintage".equals(testIdentifier.getDisplayName())) && !("JUnit Jupiter".equals(testIdentifier.getDisplayName()))) {

      flush();
      printSyncToken(TestEventMessage.START_TEST, Optional.of(testIdentifier));
    }
  }

  @Override
  public void executionSkipped(TestIdentifier testIdentifier, String reason) {
    printSyncToken(TestEventMessage.IGNORE_FAILURE_TEST_PREFIX, Optional.of(testIdentifier));
  }

  @Override
  public void executionFinished(TestIdentifier testIdentifier, TestExecutionResult testExecutionResult) {
    if (!("JUnit Vintage".equals(testIdentifier.getDisplayName())) && !("JUnit Jupiter".equals(testIdentifier.getDisplayName()))) {

      switch (testExecutionResult.getStatus()) {
        case ABORTED:
          // fall through

        case FAILED:
          printSyncToken(TestEventMessage.FAILURE_TEST_BEGIN, Optional.of(testIdentifier));
          testExecutionResult.getThrowable().ifPresent((Throwable ex) -> ex.printStackTrace(System.out));
          break;

        case SUCCESSFUL:
          flush();
          printSyncToken(TestEventMessage.FINISH_TEST, Optional.of(testIdentifier));
          flush();
          break;
      }
    }
  }

  private void flush() {
    System.out.flush();
    System.err.flush();
  }

  private void printSyncToken(@NotNull String tokenPrefix, @NotNull final Optional<TestIdentifier> identifier) {
    // simply mimic the standard structure of test class/test methods
    final StringBuilder builder = new StringBuilder();
    builder.append(tokenPrefix);
    identifier.flatMap(TestIdentifier::getSource).ifPresentOrElse((TestSource src) -> {
      if (src instanceof ClassSource) {
        builder.append(((ClassSource) src).getClassName());

      } else if (src instanceof MethodSource) {
        builder.append(((MethodSource) src).getClassName()).append(":").append(((MethodSource) src).getMethodName());

      } else {
        builder.append(identifier.map(TestIdentifier::getDisplayName));
      }

    }, () -> {

      builder.append("FAKEDESCRIPTION");

    });

    Runtime runtime = Runtime.getRuntime();
    builder.append(":memory=").append(runtime.totalMemory() - runtime.freeMemory());
    builder.append(":time=").append(System.currentTimeMillis());

    synchronized (myOutput) {
      myOutput.writeCommand(builder.toString());
      myOutput.flushSafe();
    }
  }

}
